// Parse Twilio-format SMS payload and build AI prompt.
// NO $env access — secrets are read via expressions in HTTP Request nodes.
const from = ($json.body?.From || $json.From || '').toString();
const to = ($json.body?.To || $json.To || '').toString();
const text = ($json.body?.Body || $json.Body || '').toString().trim();
const messageSid = ($json.body?.MessageSid || $json.MessageSid || 'SMdemo').toString();
const profileName = ($json.body?.ProfileName || $json.ProfileName || '').toString();

const bookingIntent = /(book|appointment|schedule|tomorrow|today|monday|tuesday|wednesday|thursday|friday|saturday|am|pm|oil|brake|tires?|diagnostic|repair|service)/i.test(text);

let serviceType = 'general service';
if (/oil/i.test(text)) serviceType = 'oil change';
else if (/brake/i.test(text)) serviceType = 'brake service';
else if (/tire|tyre/i.test(text)) serviceType = 'tire service';
else if (/diagnostic/i.test(text)) serviceType = 'diagnostic';
else if (/battery/i.test(text)) serviceType = 'battery service';
else if (/engine/i.test(text)) serviceType = 'engine repair';

const currentDate = new Date().toISOString();

const systemPrompt = `You are AutoShop AI, an SMS booking assistant for an auto repair shop.\nYour job:\n1. Reply like a real service advisor by SMS.\n2. Be concise, helpful, and natural.\n3. If the customer wants to book, collect missing info.\n4. Extract booking info when present.\n5. Never use markdown.\n6. Return STRICT JSON only.\n\nBusiness context:\n- Shop name: AutoShop AI\n- Channel: SMS\n- Goal: convert inbound SMS into appointment booking\n- Timezone: America/Chicago\n- Current timestamp: ${currentDate}\n\nReturn JSON exactly in this shape:\n{\n  \"reply_text\": \"string\",\n  \"booking_intent\": true,\n  \"customer_name\": \"string\",\n  \"service_type\": \"string\",\n  \"requested_time_text\": \"ISO 8601 datetime string e.g. 2026-03-10T10:00:00-06:00 or empty string if unknown\",\n  \"needs_more_info\": true,\n  \"calendar_summary\": \"string\",\n  \"calendar_description\": \"string\"\n}\n\nRules:\n- booking_intent = true if the person appears to want service or scheduling.\n- If date/time is unclear, ask for it in reply_text and set needs_more_info = true.\n- If service type is unclear, ask for it.\n- requested_time_text MUST be a valid ISO 8601 string when a specific date and time is known. Use America/Chicago timezone offset (-06:00 CDT or -05:00 CST). Empty string if unknown.\n- Set needs_more_info = false only when you have: service type AND specific date AND specific time.\n- Keep reply_text short enough for SMS.\n- calendar_summary should be short.\n- calendar_description should include the original SMS.`;

const userPrompt = `Inbound customer SMS:\nFrom: ${from}\nProfile Name: ${profileName}\nMessage: ${text}\n\nHeuristic booking intent: ${bookingIntent}\nHeuristic service type: ${serviceType}`;

return [{
  json: {
    from,
    to,
    body: text,
    message_sid: messageSid,
    profile_name: profileName,
    booking_intent_heuristic: bookingIntent,
    service_type_heuristic: serviceType,
    openai_request_body: JSON.stringify({
      model: 'gpt-4o-mini',
      temperature: 0.2,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    })
  }
}];

// Parse OpenAI response — no $env needed
const raw = $json.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    reply_text: 'Thanks for contacting AutoShop AI. What service do you need and what day/time works for you?',
    booking_intent: true,
    customer_name: '',
    service_type: 'general service',
    requested_time_text: '',
    needs_more_info: true,
    calendar_summary: 'AutoShop appointment inquiry',
    calendar_description: `Raw AI parse failed. Original response: ${raw}`
  };
}

const base = $('Prepare AI Prompt').first().json;

return [{
  json: {
    ...base,
    ai_raw: raw,
    reply_text: parsed.reply_text || 'Thanks for contacting AutoShop AI. What service do you need?',
    booking_intent: !!parsed.booking_intent,
    customer_name: parsed.customer_name || '',
    service_type: parsed.service_type || base.service_type_heuristic || 'general service',
    requested_time_text: parsed.requested_time_text || '',
    needs_more_info: parsed.needs_more_info !== undefined ? !!parsed.needs_more_info : true,
    calendar_summary: parsed.calendar_summary || 'AutoShop appointment inquiry',
    calendar_description: parsed.calendar_description || ''
  }
}];

// Calendar integration placeholder — no $env, no external calls.
// Google Calendar will be connected via n8n credential UI once OAuth2 is configured.
// For now, detect booking intent and prepare data for future calendar integration.
const ai = $json;
const canBook = ai.booking_intent && !ai.needs_more_info && ai.requested_time_text;

let calendarStatus = 'not_configured';
let googleEventId = null;
let googleEventLink = null;

if (!canBook) {
  calendarStatus = ai.booking_intent ? 'needs_more_info' : 'no_booking_intent';
} else {
  const start = new Date(ai.requested_time_text);
  if (isNaN(start.getTime())) {
    calendarStatus = 'invalid_time';
  } else {
    calendarStatus = 'booking_detected_calendar_pending';
  }
}

return [{
  json: {
    ...ai,
    google_event_id: googleEventId,
    google_event_link: googleEventLink,
    calendar_status: calendarStatus
  }
}];

// Build final reply and Twilio config.
// Non-secret configuration — edit these values directly in n8n UI:
const DEMO_RECIPIENT = '+37067577829';

const data = $input.first().json;

return [{
  json: {
    ...data,
    final_reply_text: data.reply_text,
    demo_to: DEMO_RECIPIENT
  }
}];

// Format clean demo response for webhook caller.
const tw = $json;
const data = $('Compose Demo Reply').first().json;

return [{
  json: {
    demo: true,
    inbound_message: data.body,
    from: data.from,
    ai_reply: data.reply_text,
    booking_intent: data.booking_intent,
    service_type: data.service_type,
    requested_time_text: data.requested_time_text || '',
    needs_more_info: data.needs_more_info,
    calendar_summary: data.calendar_summary,
    calendar_status: data.calendar_status || 'skipped',
    google_event_id: data.google_event_id || null,
    google_event_link: data.google_event_link || null,
    twilio_to: data.demo_to,
    twilio_message_sid: tw.sid || null,
    twilio_status: tw.status || null,
    twilio_error: tw.message || null,
    model: 'gpt-4o-mini'
  }
}];
